function safeParse(raw) {
  if (!raw) {
    return null;
  }
  try {
    return JSON.parse(raw);
  } catch (error) {
    return { __parseError: error.message };
  }
}

const healthExec = ($('Health: Run research-health').item.json || {});
const statsExec = ($('Health: Run research-stats').item.json || {});
const healthStdout = (healthExec.stdout || '').toString().trim();
const statsStdout = (statsExec.stdout || '').toString().trim();
const healthData = safeParse(healthStdout);
const statsData = safeParse(statsStdout);
const healthExitCode = Number(healthExec.exitCode || 0);
const statsExitCode = Number(statsExec.exitCode || 0);

// Existing: actionable checks for alert routing
const actionableChecks = [];
if (healthData && Array.isArray(healthData.checks)) {
  for (const check of healthData.checks) {
    const status = (check.status || '').toUpperCase();
    const deferred = Boolean(check.data && check.data.deferred);
    if (status === 'RED' || (status === 'YELLOW' && !deferred)) {
      actionableChecks.push({
        checkName: check.check_name,
        status,
        message: (check.message || '').replace(/\s+/g, ' ').trim(),
      });
    }
  }
}
if (healthData && healthData.__parseError) {
  actionableChecks.push({ checkName: 'health_parse', status: 'RED', message: 'Unable to parse research-health JSON: ' + healthData.__parseError });
}
if (statsData && statsData.__parseError) {
  actionableChecks.push({ checkName: 'stats_parse', status: 'RED', message: 'Unable to parse research-stats JSON: ' + statsData.__parseError });
}

const derivedStatus = healthExitCode !== 0 || statsExitCode !== 0 || actionableChecks.some((c) => c.status === 'RED')
  ? 'RED'
  : actionableChecks.length > 0
    ? 'YELLOW'
    : (healthData && healthData.summary) || 'GREEN';

// Existing: stats headline (preserved for Health: Format Alert compatibility)
const statsHeadline = statsData && !statsData.__parseError
  ? {
      totalDocs: Number(statsData.total_docs || 0),
      totalClaims: Number(statsData.total_claims || 0),
      acquisitionNew: Number(statsData.acquisition_new || 0),
      acquisitionCached: Number(statsData.acquisition_cached || 0),
      acquisitionErrors: Number(statsData.acquisition_errors || 0),
      docsByFamily: statsData.docs_by_family || {},
    }
  : null;

// WP3-C: overall_category from research-health
const overallCategory = (healthData && !healthData.__parseError)
  ? (healthData.overall_category || 'no_data')
  : 'no_data';

// WP3-C: per-pipeline status derived from pipeline_failed check data
const KNOWN_PIPELINES = ['academic', 'reddit', 'blog', 'youtube', 'github', 'freshness'];
const runCount = Number((healthData && healthData.run_count) || 0);
let errorPipelines = [];
let blockedPipelines = [];
if (healthData && Array.isArray(healthData.checks)) {
  const pfCheck = healthData.checks.find((c) => c.check_name === 'pipeline_failed');
  if (pfCheck && pfCheck.data) {
    errorPipelines = Array.isArray(pfCheck.data.error_pipelines) ? pfCheck.data.error_pipelines : [];
    blockedPipelines = Array.isArray(pfCheck.data.blocked_pipelines) ? pfCheck.data.blocked_pipelines : [];
  }
}
const pipelineStatuses = KNOWN_PIPELINES.map((name) => {
  let status = 'ok';
  let note = null;
  if (runCount === 0) {
    status = 'unknown';
    note = 'no_run_data';
  } else if (blockedPipelines.includes(name)) {
    status = 'blocked';
  } else if (errorPipelines.includes(name)) {
    status = 'error';
  }
  return { pipeline: name, status, note };
});

// WP3-C: knowledge store summary
const knowledgeStore = statsData && !statsData.__parseError
  ? {
      totalDocs: Number(statsData.total_docs || 0),
      totalClaims: Number(statsData.total_claims || 0),
      docsByFamily: statsData.docs_by_family || {},
      gateDistribution: statsData.gate_distribution || {},
      dispositionDistribution: statsData.disposition_distribution || {},
      recentNew: Number(statsData.acquisition_new || 0),
      recentCached: Number(statsData.acquisition_cached || 0),
    }
  : null;

// WP3-C: review queue
const rqRaw = (statsData && !statsData.__parseError && statsData.review_queue) || {};
const reviewQueue = {
  queueDepth: Number(rqRaw.queue_depth || 0),
  byStatus: rqRaw.by_status || {},
  byGate: rqRaw.by_gate || {},
};

// WP3-C: provider routing summary
const rsRaw = (statsData && !statsData.__parseError && statsData.routing_summary) || {};
const prdRaw = (statsData && !statsData.__parseError && statsData.provider_route_distribution) || {};
const pfcRaw = (statsData && !statsData.__parseError && statsData.provider_failure_counts) || {};
const providerRouting = {
  totalRouted: Number(rsRaw.total_routed || 0),
  direct: Number(rsRaw.direct_count || 0),
  escalated: Number(rsRaw.escalation_count || 0),
  fallback: Number(rsRaw.fallback_count || 0),
  byProvider: prdRaw,
  failureCounts: pfcRaw,
};

// WP3-C: compact operator summary text (table-like for n8n execution panel)
const statusIcon = (s) => s === 'ok' ? '\u2705' : s === 'error' ? '\u274c' : s === 'blocked' ? '\U0001f6ab' : '\u2753';
const pipelineLines = pipelineStatuses.map((p) => statusIcon(p.status) + ' ' + p.pipeline + (p.note ? ' (' + p.note + ')' : '')).join(' | ');
const ksLine = knowledgeStore
  ? 'docs=' + knowledgeStore.totalDocs + ' claims=' + knowledgeStore.totalClaims + ' new=' + knowledgeStore.recentNew
  : 'stats_unavailable';
const rqLine = 'queue=' + reviewQueue.queueDepth;
const routeLine = providerRouting.totalRouted > 0
  ? 'routed=' + providerRouting.totalRouted + ' direct=' + providerRouting.direct + ' esc=' + providerRouting.escalated + ' fb=' + providerRouting.fallback
  : 'no_routing_data';
const operatorSummary = [
  'Status: ' + derivedStatus + ' (' + overallCategory + ')',
  'Pipelines: ' + pipelineLines,
  'KS: ' + ksLine,
  'Queue: ' + rqLine,
  'Routing: ' + routeLine,
].join('\n');

return [{
  json: {
    shouldAlert: derivedStatus === 'RED' || actionableChecks.length > 0,
    overallStatus: derivedStatus,
    overallCategory,
    runCount,
    actionableChecks,
    statsHeadline,
    pipelineStatuses,
    knowledgeStore,
    reviewQueue,
    providerRouting,
    operatorSummary,
    healthExitCode,
    statsExitCode,
    healthStdout: healthStdout.substring(0, 1200),
    statsStdout: statsStdout.substring(0, 800),
    healthStderr: (healthExec.stderr || '').toString().substring(0, 500),
    statsStderr: (statsExec.stderr || '').toString().substring(0, 500),
    timestamp: new Date().toISOString(),
  },
}];

const data = $('Health: Parse Output').item.json;
const RED = 16711680;
const YELLOW = 16744448;

// Embed color from overall status (RED or YELLOW — health alerts only fire on degraded states)
const color = data.overallStatus === 'RED' ? RED : YELLOW;

// Description: check count + overallCategory if known (overallCategory added in WP3-C)
let description;
if (data.actionableChecks && data.actionableChecks.length === 1) {
  description = data.actionableChecks[0].checkName + ' detected';
} else if (data.actionableChecks && data.actionableChecks.length > 1) {
  description = data.actionableChecks.length + ' checks need attention';
} else {
  description = data.overallStatus;
}
if (data.overallCategory && data.overallCategory !== 'no_data') {
  description = description + ' (' + data.overallCategory + ')';
}

const fields = [];

// WP3-D: per-pipeline status row using pipelineStatuses (added in WP3-C)
if (Array.isArray(data.pipelineStatuses) && data.pipelineStatuses.length > 0) {
  const STATUS_ICONS = { ok: '✅', error: '❌', blocked: '⚠️', unknown: '❓' };
  const pipelineRow = data.pipelineStatuses.map(function(p) {
    return (STATUS_ICONS[p.status] || '❓') + ' ' + p.pipeline;
  }).join('  ');
  fields.push({ name: 'Pipelines', value: pipelineRow, inline: false });
}

// WP3-D: compact knowledge store summary using knowledgeStore (added in WP3-C)
const ks = data.knowledgeStore;
if (ks && ks.totalDocs != null) {
  fields.push({
    name: 'Knowledge Store',
    value: 'docs=' + ks.totalDocs + '  claims=' + ks.totalClaims + '  new=' + ks.recentNew,
    inline: false
  });
} else {
  // Fallback to statsHeadline for pre-WP3-C compatibility
  const stats = data.statsHeadline || {};
  if (stats.totalDocs != null) {
    fields.push({ name: 'Docs', value: String(stats.totalDocs), inline: true });
    fields.push({ name: 'New', value: String(stats.acquisitionNew != null ? stats.acquisitionNew : 0), inline: true });
  }
}

// WP3-D: review queue depth using reviewQueue (added in WP3-C)
const rq = data.reviewQueue;
if (rq && rq.queueDepth != null) {
  fields.push({ name: 'Review Queue', value: String(rq.queueDepth) + ' pending', inline: true });
}

// Existing: run count
if (data.runCount != null) {
  fields.push({ name: 'Runs', value: String(data.runCount), inline: true });
}

// Existing: actionable checks (up to 3, truncated to Discord field limit)
if (data.actionableChecks && data.actionableChecks.length > 0) {
  const checkLines = data.actionableChecks.slice(0, 3).map(function(c) {
    return (c.status === 'RED' ? '[RED]' : '[YLW]') + ' ' + c.checkName + ': ' + c.message.substring(0, 80);
  }).join('\n');
  const suffix = data.actionableChecks.length > 3 ? '\n+' + (data.actionableChecks.length - 3) + ' more' : '';
  fields.push({ name: 'Actionable Checks', value: (checkLines + suffix).substring(0, 300), inline: false });
}

// Existing: command exit codes if non-zero
if (data.healthExitCode !== 0 || data.statsExitCode !== 0) {
  fields.push({ name: 'Command Exit', value: 'health=' + data.healthExitCode + ', stats=' + data.statsExitCode, inline: false });
}

const embed = {
  title: 'RIS Health: ' + data.overallStatus,
  description: description,
  color: color,
  fields: fields,
  footer: { text: 'RIS | health' },
  timestamp: new Date().toISOString(),
};
const rawWebhookUrl = '__RIS_OPERATOR_WEBHOOK_URL__';
const webhookUrl = (String(rawWebhookUrl).startsWith('http://') || String(rawWebhookUrl).startsWith('https://')) ? String(rawWebhookUrl).trim() : '';
const notifyEnabled = webhookUrl.length > 0;
return [{ json: { embeds: [embed], webhookUrl, notifyEnabled } }];

const stdout = ($json.stdout || '').toString();
const lines = stdout.split('\n');
const timestamp = new Date().toISOString();
const exitCode = Number($json.exitCode || 0);
let docs_accepted = 0;
let docs_rejected = 0;
const errors = [];
for (const line of lines) {
  const t = line.trim();
  if (!t) continue;
  if (/^Acquired:/i.test(t)) {
    docs_accepted++;
  } else if (/^Rejected[\s|:]/i.test(t)) {
    docs_rejected++;
  } else if (/^Error:/i.test(t) || /^Warning:/i.test(t)) {
    errors.push(t.substring(0, 200));
  }
}
if (docs_accepted === 0 && docs_rejected === 0) {
  let sa = 0, st = 0;
  const re = /Search complete: (\d+)\/(\d+) papers ingested/gi;
  let m;
  while ((m = re.exec(stdout)) !== null) {
    sa += parseInt(m[1], 10);
    st += parseInt(m[2], 10);
  }
  if (st > 0) { docs_accepted = sa; docs_rejected = st - sa; }
}
if (exitCode !== 0) errors.push('exit_code=' + exitCode);
const docs_fetched = docs_accepted + docs_rejected;
const statusLabel = errors.length > 0 ? '⚠️ Academic: ' + docs_accepted + ' docs | ' + errors.length + ' warning(s)' : '✅ Academic: ' + docs_accepted + ' docs ingested';
return [{ json: { pipeline: 'academic', docs_fetched, docs_evaluated: docs_fetched, docs_accepted, docs_rejected, docs_review: 0, new_claims: 0, duration_seconds: null, errors, exit_code: exitCode, timestamp, status_label: statusLabel } }];

const execNode = $json || {};
const stderrRaw = (execNode.stderr || '').toString().trim().substring(0, 300);
const stdout = (execNode.stdout || '').toString();
const stdoutTail = (stdout.length > 200 ? stdout.substring(stdout.length - 200) : stdout).trim();
const exitCode = execNode.exitCode;

// WP3-D: partial parse — extract accepted/rejected counts even in error path
let partialAccepted = 0, partialRejected = 0;
stdout.split('\n').forEach(function(line) {
  const t = line.trim();
  if (/^Acquired:/i.test(t)) { partialAccepted++; }
  else if (/^Rejected[\s|:]/i.test(t)) { partialRejected++; }
});
if (partialAccepted === 0 && partialRejected === 0) {
  const re = /Search complete: (\d+)\/(\d+) papers ingested/gi;
  let m;
  while ((m = re.exec(stdout)) !== null) {
    partialAccepted += parseInt(m[1], 10);
    partialRejected += parseInt(m[2], 10) - parseInt(m[1], 10);
  }
}
const hasPartial = partialAccepted > 0 || partialRejected > 0;
const description = 'Exit ' + exitCode + (hasPartial ? ' — partial: ' + partialAccepted + ' accepted, ' + partialRejected + ' rejected' : '');

const embed = {
  title: 'Pipeline Error: Academic',
  description: description,
  color: 16711680,
  fields: [],
  footer: { text: 'RIS | academic' },
  timestamp: new Date().toISOString(),
};
if (stderrRaw.length > 0) {
  embed.fields.push({ name: 'Error Output', value: stderrRaw, inline: false });
}
if (stdoutTail.length > 0) {
  embed.fields.push({ name: 'Last Output', value: stdoutTail, inline: false });
}
const rawWebhookUrl = '__RIS_OPERATOR_WEBHOOK_URL__';
const webhookUrl = (String(rawWebhookUrl).startsWith('http://') || String(rawWebhookUrl).startsWith('https://')) ? String(rawWebhookUrl).trim() : '';
const notifyEnabled = webhookUrl.length > 0;
const statusLabel = '❌ Academic: exit ' + exitCode + (stderrRaw.length > 0 ? ' | ' + stderrRaw.substring(0, 60) : '');
return [{ json: { embeds: [embed], webhookUrl, notifyEnabled, status_label: statusLabel } }];

