  for (const check of healthData.checks) {
    const status = (check.status || '').toUpperCase();
    const deferred = Boolean(check.data && check.data.deferred);
    if (status === 'RED' || (status === 'YELLOW' && !deferred)) {
      actionableChecks.push({
        checkName: check.check_name,
        status,
        message: (check.message || '').replace(/\s+/g, ' ').trim(),
      });
    }
  }
}
if (healthData && healthData.__parseError) {
  actionableChecks.push({ checkName: 'health_parse', status: 'RED', message: 'Unable to parse research-health: ' + healthData.__parseError });
}
